class Solution {
    public int numMusicPlaylists(int n, int goal, int k) {
        long MOD = 1000000007;
        long res = 1;
        for (int i = 1; i <= goal; i++) {
            res = res * (n - i + 1) % MOD * (i - k) % MOD;
        }
        return (int) res;
    }
}
